export const getUnitsForLanguage = (lang: Language): Unit[] => {
  const syllabus = SYLLABUS_TITLES[lang] || SYLLABUS_TITLES['fr'];
  // Correctly mapping each language to its own content object
  const manualContent = lang === 'fr' ? CONTENT_FR : lang === 'ar' ? CONTENT_AR : CONTENT_EN;
  const fallbackContent = CONTENT_FR;

  return syllabus.map((item, index) => {
    const unitId = index + 1;
    // Development Lock Logic: Units 1 to 30 are now active
    const isActiveDev = unitId <= 30; 
    
    // Cycle colors
    const colors = ["bg-green-500", "bg-blue-500", "bg-purple-500", "bg-orange-500", "bg-rose-500", "bg-teal-500", "bg-indigo-500"];
    const color = isActiveDev ? colors[index % colors.length] : "bg-gray-400"; // Grey out future units

    let questions = manualContent[unitId];
    
    // Safety Fallback if translation missing (Should not happen for 1-12 anymore)
    if (!questions) {
        const base = fallbackContent[unitId] || fallbackContent[1];
        // If falling back, we append language prefix to ID to avoid React key collisions
        questions = base.map(q => ({ ...q, id: String(q.id).replace('fr-', `${lang}-`) }));
    }

    return {
      id: unitId,
      title: item.t,
      description: isActiveDev ? item.d : (lang === 'fr' ? "En développement..." : lang === 'ar' ? "قريباً..." : "Coming soon..."),
      color: color,
      icon: "star",
      lessons: [{ id: `l${unitId}-${lang}`, title: item.t, questions }]
    };
  });
};

export const UNITS_DB = getUnitsForLanguage('fr');